final:
module RefModule(
    input clk,
    input reset_n,
    output reg [3:0] count
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
        if (!reset_n)
            count <= 4'b1111;
        else
            count <= count - 1;
    end
endmodule
